using System.ComponentModel.DataAnnotations;

namespace sv_05d9445b33e5485bb17828b852aeac8a.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, MinimumLength = 1, ErrorMessage = "Name must be between 1 and 100 characters.")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Quantity is required.")]
    [Range(0, int.MaxValue, ErrorMessage = "Quantity must be 0 or greater.")]
    public int Quantity { get; set; }

    [Required(ErrorMessage = "Unit Price is required.")]
    [Range(0.01, double.MaxValue, ErrorMessage = "Unit Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    public static readonly string[] Categories = ["Electronics", "Clothing", "Food", "Other"];
}

using sv_05d9445b33e5485bb17828b852aeac8a.Models;

namespace sv_05d9445b33e5485bb17828b852aeac8a.Services;

public class InventoryService
{
    private readonly List<Product> _products;
    private int _nextId;
    private readonly Lock _lock = new();

    public InventoryService()
    {
        _products =
        [
            new Product { Id = 1, Name = "Wireless Headphones", Quantity = 25, UnitPrice = 59.99m, Category = "Electronics" },
            new Product { Id = 2, Name = "USB-C Cable", Quantity = 150, UnitPrice = 12.99m, Category = "Electronics" },
            new Product { Id = 3, Name = "Cotton T-Shirt", Quantity = 80, UnitPrice = 19.95m, Category = "Clothing" },
            new Product { Id = 4, Name = "Running Shoes", Quantity = 30, UnitPrice = 89.99m, Category = "Clothing" },
            new Product { Id = 5, Name = "Organic Coffee Beans", Quantity = 60, UnitPrice = 14.50m, Category = "Food" },
            new Product { Id = 6, Name = "Granola Bars (12-pack)", Quantity = 45, UnitPrice = 8.99m, Category = "Food" },
        ];
        _nextId = 7;
    }

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => Clone(p)).ToList());
        }
    }

    public Task<Product?> GetByIdAsync(int id)
    {
        lock (_lock)
        {
            var product = _products.FirstOrDefault(p => p.Id == id);
            return Task.FromResult(product is null ? null : Clone(product));
        }
    }

    public Task AddAsync(Product product)
    {
        lock (_lock)
        {
            product.Id = _nextId++;
            _products.Add(Clone(product));
        }
        return Task.CompletedTask;
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is not null)
            {
                existing.Name = product.Name;
                existing.Quantity = product.Quantity;
                existing.UnitPrice = product.UnitPrice;
                existing.Category = product.Category;
            }
        }
        return Task.CompletedTask;
    }

    private static Product Clone(Product p) => new()
    {
        Id = p.Id,
        Name = p.Name,
        Quantity = p.Quantity,
        UnitPrice = p.UnitPrice,
        Category = p.Category
    };
}

